import random

def guess_number():
    number = random.randint(1, 20)
    while True:
        guess = int(input("Guess a number between 1 and 20: "))
        if guess == number:
            print("Congratulations! You guessed the correct number.")
            break
        elif guess < number:
            print("Too low, try again!")
        else:
            print("Too high, try again!")

guess_number()

