import re

def clean_text(text):
    return re.sub(r'\s+', ' ', text).strip()

def generate_response(prompt):
    if "weather" in prompt.lower():
        response = "The weather is beautiful today."
    elif "news" in prompt.lower():
        response = "Breaking news: Something big happened!"
    elif "movie" in prompt.lower():
        response = "I recommend watching Titanic."
    else:
        response = "I'm not sure what you're asking about."

    return clean_text(response)

